import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";import{f as e}from"./app.862eb2af.js";const p={},r=e('<h1 id="\u95E8\u9762\u6A21\u5F0F-\u5916\u89C2\u6A21\u5F0F" tabindex="-1"><a class="header-anchor" href="#\u95E8\u9762\u6A21\u5F0F-\u5916\u89C2\u6A21\u5F0F" aria-hidden="true">#</a> \u95E8\u9762\u6A21\u5F0F\uFF08\u5916\u89C2\u6A21\u5F0F\uFF09</h1><p>\u524D\u9762\u6211\u4EEC\u5DF2\u7ECF\u5B66\u4E60\u4E86\u4EE3\u7406\u6A21\u5F0F\u3001\u6865\u63A5\u6A21\u5F0F\u3001\u88C5\u9970\u5668\u6A21\u5F0F\u3001\u9002\u914D\u5668\u6A21\u5F0F\uFF0C\u8FD9 4 \u79CD\u7ED3\u6784\u578B\u8BBE\u8BA1\u6A21\u5F0F\u3002\u4ECA\u5929\uFF0C\u6211\u4EEC\u518D\u6765\u5B66\u4E60\u4E00\u79CD\u65B0\u7684\u7ED3\u6784\u578B\u6A21\u5F0F\uFF1A\u95E8\u9762\u6A21\u5F0F\u3002\u95E8\u9762\u6A21\u5F0F\u539F\u7406\u548C\u5B9E\u73B0\u90FD\u7279\u522B\u7B80\u5355\uFF0C\u5E94\u7528\u573A\u666F\u4E5F\u6BD4\u8F83\u660E\u786E\uFF0C\u4E3B\u8981\u5728\u63A5\u53E3\u8BBE\u8BA1\u65B9\u9762\u4F7F\u7528\u3002</p><p>\u5982\u679C\u4F60\u5E73\u65F6\u7684\u5DE5\u4F5C\u6D89\u53CA\u63A5\u53E3\u5F00\u53D1\uFF0C\u4E0D\u77E5\u9053\u4F60\u6709\u6CA1\u6709\u9047\u5230\u5173\u4E8E\u63A5\u53E3\u7C92\u5EA6\u7684\u95EE\u9898\u5462\uFF1F</p><p>\u4E3A\u4E86\u4FDD\u8BC1\u63A5\u53E3\u7684\u53EF\u590D\u7528\u6027\uFF08\u6216\u8005\u53EB\u901A\u7528\u6027\uFF09\uFF0C\u6211\u4EEC\u9700\u8981\u5C06\u63A5\u53E3\u5C3D\u91CF\u8BBE\u8BA1\u5F97\u7EC6\u7C92\u5EA6\u4E00\u70B9\uFF0C\u804C\u8D23\u5355\u4E00\u4E00\u70B9\u3002\u4F46\u662F\uFF0C\u5982\u679C\u63A5\u53E3\u7684\u7C92\u5EA6\u8FC7\u5C0F\uFF0C\u5728\u63A5\u53E3\u7684\u4F7F\u7528\u8005\u5F00\u53D1\u4E00\u4E2A\u4E1A\u52A1\u529F\u80FD\u65F6\uFF0C\u5C31\u4F1A\u5BFC\u81F4\u9700\u8981\u8C03\u7528 n \u591A\u7EC6\u7C92\u5EA6\u7684\u63A5\u53E3\u624D\u80FD\u5B8C\u6210\u3002\u8C03\u7528\u8005\u80AF\u5B9A\u4F1A\u62B1\u6028\u63A5\u53E3\u4E0D\u597D\u7528\u3002</p><p>\u76F8\u53CD\uFF0C\u5982\u679C\u63A5\u53E3\u7C92\u5EA6\u8BBE\u8BA1\u5F97\u592A\u5927\uFF0C\u4E00\u4E2A\u63A5\u53E3\u8FD4\u56DE n \u591A\u6570\u636E\uFF0C\u8981\u505A n \u591A\u4E8B\u60C5\uFF0C\u5C31\u4F1A\u5BFC\u81F4\u63A5\u53E3\u4E0D\u591F\u901A\u7528\u3001\u53EF\u590D\u7528\u6027\u4E0D\u597D\u3002\u63A5\u53E3\u4E0D\u53EF\u590D\u7528\uFF0C\u90A3\u9488\u5BF9\u4E0D\u540C\u7684\u8C03\u7528\u8005\u7684\u4E1A\u52A1\u9700\u6C42\uFF0C\u6211\u4EEC\u5C31\u9700\u8981\u5F00\u53D1\u4E0D\u540C\u7684\u63A5\u53E3\u6765\u6EE1\u8DB3\uFF0C\u8FD9\u5C31\u4F1A\u5BFC\u81F4\u7CFB\u7EDF\u7684\u63A5\u53E3\u65E0\u9650\u81A8\u80C0\u3002</p><p>\u90A3\u5982\u4F55\u6765\u89E3\u51B3\u63A5\u53E3\u7684\u53EF\u590D\u7528\u6027\uFF08\u901A\u7528\u6027\uFF09\u548C\u6613\u7528\u6027\u4E4B\u95F4\u7684\u77DB\u76FE\u5462\uFF1F</p><h2 id="\u95E8\u9762\u6A21\u5F0F\u7684\u539F\u7406\u4E0E\u5B9E\u73B0" tabindex="-1"><a class="header-anchor" href="#\u95E8\u9762\u6A21\u5F0F\u7684\u539F\u7406\u4E0E\u5B9E\u73B0" aria-hidden="true">#</a> \u95E8\u9762\u6A21\u5F0F\u7684\u539F\u7406\u4E0E\u5B9E\u73B0</h2><p>\u95E8\u9762\u6A21\u5F0F\uFF0C\u4E5F\u53EB\u5916\u89C2\u6A21\u5F0F\uFF0C\u82F1\u6587\u5168\u79F0\u662F Facade Design Pattern\u3002\u5728 GoF \u7684\u300A\u8BBE\u8BA1\u6A21\u5F0F\u300B\u4E00\u4E66\u4E2D\uFF0C\u95E8\u9762\u6A21\u5F0F\u662F\u8FD9\u6837\u5B9A\u4E49\u7684\uFF1A</p><blockquote><p>Provide a unified interface to a set of interfaces in a subsystem. Facade Pattern defines a higher-level interface that makes the subsystem easier to use.</p></blockquote><p>\u7FFB\u8BD1\u6210\u4E2D\u6587\u5C31\u662F\uFF1A\u95E8\u9762\u6A21\u5F0F\u4E3A\u5B50\u7CFB\u7EDF\u63D0\u4F9B\u4E00\u7EC4\u7EDF\u4E00\u7684\u63A5\u53E3\uFF0C\u5B9A\u4E49\u4E00\u7EC4\u9AD8\u5C42\u63A5\u53E3\u8BA9\u5B50\u7CFB\u7EDF\u66F4\u6613\u7528\u3002</p><p>\u8FD9\u4E2A\u5B9A\u4E49\u5F88\u7B80\u6D01\uFF0C\u6211\u518D\u8FDB\u4E00\u6B65\u89E3\u91CA\u4E00\u4E0B\u3002</p><p>\u5047\u8BBE\u6709\u4E00\u4E2A\u7CFB\u7EDF A\uFF0C\u63D0\u4F9B\u4E86 a\u3001b\u3001c\u3001d \u56DB\u4E2A\u63A5\u53E3\u3002\u7CFB\u7EDF B \u5B8C\u6210\u67D0\u4E2A\u4E1A\u52A1\u529F\u80FD\uFF0C\u9700\u8981\u8C03\u7528 A \u7CFB\u7EDF\u7684 a\u3001b\u3001d \u63A5\u53E3\u3002\u5229\u7528\u95E8\u9762\u6A21\u5F0F\uFF0C\u6211\u4EEC\u63D0\u4F9B\u4E00\u4E2A\u5305\u88F9 a\u3001b\u3001d \u63A5\u53E3\u8C03\u7528\u7684\u95E8\u9762\u63A5\u53E3 x\uFF0C\u7ED9\u7CFB\u7EDF B \u76F4\u63A5\u4F7F\u7528\u3002</p><p>\u4E0D\u77E5\u9053\u4F60\u4F1A\u4E0D\u4F1A\u6709\u8FD9\u6837\u7684\u7591\u95EE\uFF0C\u8BA9\u7CFB\u7EDF B \u76F4\u63A5\u8C03\u7528 a\u3001b\u3001d \u611F\u89C9\u6CA1\u6709\u592A\u5927\u95EE\u9898\u5440\uFF0C\u4E3A\u4EC0\u4E48\u8FD8\u8981\u63D0\u4F9B\u4E00\u4E2A\u5305\u88F9 a\u3001b\u3001d \u7684\u63A5\u53E3 x \u5462\uFF1F\u5173\u4E8E\u8FD9\u4E2A\u95EE\u9898\uFF0C\u6211\u901A\u8FC7\u4E00\u4E2A\u5177\u4F53\u7684\u4F8B\u5B50\u6765\u89E3\u91CA\u4E00\u4E0B\u3002</p><p>\u5047\u8BBE\u6211\u4EEC\u521A\u521A\u63D0\u5230\u7684\u7CFB\u7EDF A \u662F\u4E00\u4E2A\u540E\u7AEF\u670D\u52A1\u5668\uFF0C\u7CFB\u7EDF B \u662F App \u5BA2\u6237\u7AEF\u3002App \u5BA2\u6237\u7AEF\u901A\u8FC7\u540E\u7AEF\u670D\u52A1\u5668\u63D0\u4F9B\u7684\u63A5\u53E3\u6765\u83B7\u53D6\u6570\u636E\u3002\u6211\u4EEC\u77E5\u9053\uFF0CApp \u548C\u670D\u52A1\u5668\u4E4B\u95F4\u662F\u901A\u8FC7\u79FB\u52A8\u7F51\u7EDC\u901A\u4FE1\u7684\uFF0C\u7F51\u7EDC\u901A\u4FE1\u8017\u65F6\u6BD4\u8F83\u591A\uFF0C\u4E3A\u4E86\u63D0\u9AD8 App \u7684\u54CD\u5E94\u901F\u5EA6\uFF0C\u6211\u4EEC\u8981\u5C3D\u91CF\u51CF\u5C11 App \u4E0E\u670D\u52A1\u5668\u4E4B\u95F4\u7684\u7F51\u7EDC\u901A\u4FE1\u6B21\u6570\u3002</p><p>\u5047\u8BBE\uFF0C\u5B8C\u6210\u67D0\u4E2A\u4E1A\u52A1\u529F\u80FD\uFF08\u6BD4\u5982\u663E\u793A\u67D0\u4E2A\u9875\u9762\u4FE1\u606F\uFF09\u9700\u8981\u201C\u4F9D\u6B21\u201D\u8C03\u7528 a\u3001b\u3001d \u4E09\u4E2A\u63A5\u53E3\uFF0C\u56E0\u81EA\u8EAB\u4E1A\u52A1\u7684\u7279\u70B9\uFF0C\u4E0D\u652F\u6301\u5E76\u53D1\u8C03\u7528\u8FD9\u4E09\u4E2A\u63A5\u53E3\u3002</p><p>\u5982\u679C\u6211\u4EEC\u73B0\u5728\u53D1\u73B0 App \u5BA2\u6237\u7AEF\u7684\u54CD\u5E94\u901F\u5EA6\u6BD4\u8F83\u6162\uFF0C\u6392\u67E5\u4E4B\u540E\u53D1\u73B0\uFF0C\u662F\u56E0\u4E3A\u8FC7\u591A\u7684\u63A5\u53E3\u8C03\u7528\u8FC7\u591A\u7684\u7F51\u7EDC\u901A\u4FE1\u3002\u9488\u5BF9\u8FD9\u79CD\u60C5\u51B5\uFF0C\u6211\u4EEC\u5C31\u53EF\u4EE5\u5229\u7528\u95E8\u9762\u6A21\u5F0F\uFF0C\u8BA9\u540E\u7AEF\u670D\u52A1\u5668\u63D0\u4F9B\u4E00\u4E2A\u5305\u88F9 a\u3001b\u3001d \u4E09\u4E2A\u63A5\u53E3\u8C03\u7528\u7684\u63A5\u53E3 x\u3002App \u5BA2\u6237\u7AEF\u8C03\u7528\u4E00\u6B21\u63A5\u53E3 x\uFF0C\u6765\u83B7\u53D6\u5230\u6240\u6709\u60F3\u8981\u7684\u6570\u636E\uFF0C\u5C06\u7F51\u7EDC\u901A\u4FE1\u7684\u6B21\u6570\u4ECE 3 \u6B21\u51CF\u5C11\u5230 1 \u6B21\uFF0C\u4E5F\u5C31\u63D0\u9AD8\u4E86 App \u7684\u54CD\u5E94\u901F\u5EA6\u3002</p><p>\u8FD9\u91CC\u4E3E\u7684\u4F8B\u5B50\u53EA\u662F\u5E94\u7528\u95E8\u9762\u6A21\u5F0F\u7684\u5176\u4E2D\u4E00\u4E2A\u610F\u56FE\uFF0C\u4E5F\u5C31\u662F\u89E3\u51B3\u6027\u80FD\u95EE\u9898\u3002\u5B9E\u9645\u4E0A\uFF0C\u4E0D\u540C\u7684\u5E94\u7528\u573A\u666F\u4E0B\uFF0C\u4F7F\u7528\u95E8\u9762\u6A21\u5F0F\u7684\u610F\u56FE\u4E5F\u4E0D\u540C\u3002\u63A5\u4E0B\u6765\uFF0C\u6211\u4EEC\u5C31\u6765\u770B\u4E00\u4E0B\u95E8\u9762\u6A21\u5F0F\u7684\u5404\u79CD\u5E94\u7528\u573A\u666F\u3002</p><h2 id="\u95E8\u9762\u6A21\u5F0F\u7684\u5E94\u7528\u573A\u666F\u4E3E\u4F8B" tabindex="-1"><a class="header-anchor" href="#\u95E8\u9762\u6A21\u5F0F\u7684\u5E94\u7528\u573A\u666F\u4E3E\u4F8B" aria-hidden="true">#</a> \u95E8\u9762\u6A21\u5F0F\u7684\u5E94\u7528\u573A\u666F\u4E3E\u4F8B</h2><p>\u5728 GoF \u7ED9\u51FA\u7684\u5B9A\u4E49\u4E2D\u63D0\u5230\uFF0C\u201C\u95E8\u9762\u6A21\u5F0F\u8BA9\u5B50\u7CFB\u7EDF\u66F4\u52A0\u6613\u7528\u201D\uFF0C\u5B9E\u9645\u4E0A\uFF0C\u5B83\u9664\u4E86\u89E3\u51B3\u6613\u7528\u6027\u95EE\u9898\u4E4B\u5916\uFF0C\u8FD8\u80FD\u89E3\u51B3\u5176\u4ED6\u5F88\u591A\u65B9\u9762\u7684\u95EE\u9898\u3002\u5173\u4E8E\u8FD9\u4E00\u70B9\uFF0C\u6211\u603B\u7ED3\u7F57\u5217\u4E86 3 \u4E2A\u5E38\u7528\u7684\u5E94\u7528\u573A\u666F\uFF0C\u4F60\u53EF\u4EE5\u53C2\u8003\u4E00\u4E0B\uFF0C\u4E3E\u4E00\u53CD\u4E09\u5730\u501F\u9274\u5230\u81EA\u5DF1\u7684\u9879\u76EE\u4E2D\u3002</p><p>\u9664\u6B64\u4E4B\u5916\uFF0C\u6211\u8FD8\u8981\u5F3A\u8C03\u4E00\u4E0B\uFF0C\u95E8\u9762\u6A21\u5F0F\u5B9A\u4E49\u4E2D\u7684\u201C\u5B50\u7CFB\u7EDF\uFF08subsystem\uFF09\u201D\u4E5F\u53EF\u4EE5\u6709\u591A\u79CD\u7406\u89E3\u65B9\u5F0F\u3002\u5B83\u65E2\u53EF\u4EE5\u662F\u4E00\u4E2A\u5B8C\u6574\u7684\u7CFB\u7EDF\uFF0C\u4E5F\u53EF\u4EE5\u662F\u66F4\u7EC6\u7C92\u5EA6\u7684\u7C7B\u6216\u8005\u6A21\u5757\u3002\u5173\u4E8E\u8FD9\u4E00\u70B9\uFF0C\u5728\u4E0B\u9762\u7684\u8BB2\u89E3\u4E2D\u4E5F\u4F1A\u6709\u4F53\u73B0\u3002</p><h3 id="_1-\u89E3\u51B3\u6613\u7528\u6027\u95EE\u9898" tabindex="-1"><a class="header-anchor" href="#_1-\u89E3\u51B3\u6613\u7528\u6027\u95EE\u9898" aria-hidden="true">#</a> 1. \u89E3\u51B3\u6613\u7528\u6027\u95EE\u9898</h3><p>\u95E8\u9762\u6A21\u5F0F\u53EF\u4EE5\u7528\u6765\u5C01\u88C5\u7CFB\u7EDF\u7684\u5E95\u5C42\u5B9E\u73B0\uFF0C\u9690\u85CF\u7CFB\u7EDF\u7684\u590D\u6742\u6027\uFF0C\u63D0\u4F9B\u4E00\u7EC4\u66F4\u52A0\u7B80\u5355\u6613\u7528\u3001\u66F4\u9AD8\u5C42\u7684\u63A5\u53E3\u3002\u6BD4\u5982\uFF0CLinux \u7CFB\u7EDF\u8C03\u7528\u51FD\u6570\u5C31\u53EF\u4EE5\u770B\u4F5C\u4E00\u79CD\u201C\u95E8\u9762\u201D\u3002\u5B83\u662F Linux \u64CD\u4F5C\u7CFB\u7EDF\u66B4\u9732\u7ED9\u5F00\u53D1\u8005\u7684\u4E00\u7EC4\u201C\u7279\u6B8A\u201D\u7684\u7F16\u7A0B\u63A5\u53E3\uFF0C\u5B83\u5C01\u88C5\u4E86\u5E95\u5C42\u66F4\u57FA\u7840\u7684 Linux \u5185\u6838\u8C03\u7528\u3002\u518D\u6BD4\u5982\uFF0CLinux \u7684 Shell \u547D\u4EE4\uFF0C\u5B9E\u9645\u4E0A\u4E5F\u53EF\u4EE5\u770B\u4F5C\u4E00\u79CD\u95E8\u9762\u6A21\u5F0F\u7684\u5E94\u7528\u3002\u5B83\u7EE7\u7EED\u5C01\u88C5\u7CFB\u7EDF\u8C03\u7528\uFF0C\u63D0\u4F9B\u66F4\u52A0\u53CB\u597D\u3001\u7B80\u5355\u7684\u547D\u4EE4\uFF0C\u8BA9\u6211\u4EEC\u53EF\u4EE5\u76F4\u63A5\u901A\u8FC7\u6267\u884C\u547D\u4EE4\u6765\u8DDF\u64CD\u4F5C\u7CFB\u7EDF\u4EA4\u4E92\u3002</p><p>\u6211\u4EEC\u524D\u9762\u4E5F\u591A\u6B21\u8BB2\u8FC7\uFF0C\u8BBE\u8BA1\u539F\u5219\u3001\u601D\u60F3\u3001\u6A21\u5F0F\u5F88\u591A\u90FD\u662F\u76F8\u901A\u7684\uFF0C\u662F\u540C\u4E00\u4E2A\u9053\u7406\u4E0D\u540C\u89D2\u5EA6\u7684\u8868\u8FF0\u3002\u5B9E\u9645\u4E0A\uFF0C\u4ECE\u9690\u85CF\u5B9E\u73B0\u590D\u6742\u6027\uFF0C\u63D0\u4F9B\u66F4\u6613\u7528\u63A5\u53E3\u8FD9\u4E2A\u610F\u56FE\u6765\u770B\uFF0C\u95E8\u9762\u6A21\u5F0F\u6709\u70B9\u7C7B\u4F3C\u4E4B\u524D\u8BB2\u5230\u7684\u8FEA\u7C73\u7279\u6CD5\u5219\uFF08\u6700\u5C11\u77E5\u8BC6\u539F\u5219\uFF09\u548C\u63A5\u53E3\u9694\u79BB\u539F\u5219\uFF1A\u4E24\u4E2A\u6709\u4EA4\u4E92\u7684\u7CFB\u7EDF\uFF0C\u53EA\u66B4\u9732\u6709\u9650\u7684\u5FC5\u8981\u7684\u63A5\u53E3\u3002\u9664\u6B64\u4E4B\u5916\uFF0C\u95E8\u9762\u6A21\u5F0F\u8FD8\u6709\u70B9\u7C7B\u4F3C\u4E4B\u524D\u63D0\u5230\u5C01\u88C5\u3001\u62BD\u8C61\u7684\u8BBE\u8BA1\u601D\u60F3\uFF0C\u63D0\u4F9B\u66F4\u62BD\u8C61\u7684\u63A5\u53E3\uFF0C\u5C01\u88C5\u5E95\u5C42\u5B9E\u73B0\u7EC6\u8282\u3002</p><h3 id="_2-\u89E3\u51B3\u6027\u80FD\u95EE\u9898" tabindex="-1"><a class="header-anchor" href="#_2-\u89E3\u51B3\u6027\u80FD\u95EE\u9898" aria-hidden="true">#</a> 2. \u89E3\u51B3\u6027\u80FD\u95EE\u9898</h3><p>\u5173\u4E8E\u5229\u7528\u95E8\u9762\u6A21\u5F0F\u89E3\u51B3\u6027\u80FD\u95EE\u9898\u8FD9\u4E00\u70B9\uFF0C\u521A\u521A\u6211\u4EEC\u5DF2\u7ECF\u8BB2\u8FC7\u4E86\u3002\u6211\u4EEC\u901A\u8FC7\u5C06\u591A\u4E2A\u63A5\u53E3\u8C03\u7528\u66FF\u6362\u4E3A\u4E00\u4E2A\u95E8\u9762\u63A5\u53E3\u8C03\u7528\uFF0C\u51CF\u5C11\u7F51\u7EDC\u901A\u4FE1\u6210\u672C\uFF0C\u63D0\u9AD8 App \u5BA2\u6237\u7AEF\u7684\u54CD\u5E94\u901F\u5EA6\u3002\u6240\u4EE5\uFF0C\u5173\u4E8E\u8FD9\u70B9\uFF0C\u6211\u5C31\u4E0D\u518D\u4E3E\u4F8B\u8BF4\u660E\u4E86\u3002\u6211\u4EEC\u6765\u8BA8\u8BBA\u4E00\u4E0B\u8FD9\u6837\u4E00\u4E2A\u95EE\u9898\uFF1A\u4ECE\u4EE3\u7801\u5B9E\u73B0\u7684\u89D2\u5EA6\u6765\u770B\uFF0C\u8BE5\u5982\u4F55\u7EC4\u7EC7\u95E8\u9762\u63A5\u53E3\u548C\u975E\u95E8\u9762\u63A5\u53E3\uFF1F</p><p>\u5982\u679C\u95E8\u9762\u63A5\u53E3\u4E0D\u591A\uFF0C\u6211\u4EEC\u5B8C\u5168\u53EF\u4EE5\u5C06\u5B83\u8DDF\u975E\u95E8\u9762\u63A5\u53E3\u653E\u5230\u4E00\u5757\uFF0C\u4E5F\u4E0D\u9700\u8981\u7279\u6B8A\u6807\u8BB0\uFF0C\u5F53\u4F5C\u666E\u901A\u63A5\u53E3\u6765\u7528\u5373\u53EF\u3002\u5982\u679C\u95E8\u9762\u63A5\u53E3\u5F88\u591A\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5728\u5DF2\u6709\u7684\u63A5\u53E3\u4E4B\u4E0A\uFF0C\u518D\u91CD\u65B0\u62BD\u8C61\u51FA\u4E00\u5C42\uFF0C\u4E13\u95E8\u653E\u7F6E\u95E8\u9762\u63A5\u53E3\uFF0C\u4ECE\u7C7B\u3001\u5305\u7684\u547D\u540D\u4E0A\u8DDF\u539F\u6765\u7684\u63A5\u53E3\u5C42\u505A\u533A\u5206\u3002\u5982\u679C\u95E8\u9762\u63A5\u53E3\u7279\u522B\u591A\uFF0C\u5E76\u4E14\u5F88\u591A\u90FD\u662F\u8DE8\u591A\u4E2A\u5B50\u7CFB\u7EDF\u7684\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5C06\u95E8\u9762\u63A5\u53E3\u653E\u5230\u4E00\u4E2A\u65B0\u7684\u5B50\u7CFB\u7EDF\u4E2D\u3002</p><h3 id="_3-\u89E3\u51B3\u5206\u5E03\u5F0F\u4E8B\u52A1\u95EE\u9898" tabindex="-1"><a class="header-anchor" href="#_3-\u89E3\u51B3\u5206\u5E03\u5F0F\u4E8B\u52A1\u95EE\u9898" aria-hidden="true">#</a> 3. \u89E3\u51B3\u5206\u5E03\u5F0F\u4E8B\u52A1\u95EE\u9898</h3><p>\u5173\u4E8E\u5229\u7528\u95E8\u9762\u6A21\u5F0F\u6765\u89E3\u51B3\u5206\u5E03\u5F0F\u4E8B\u52A1\u95EE\u9898\uFF0C\u6211\u4EEC\u901A\u8FC7\u4E00\u4E2A\u4F8B\u5B50\u6765\u89E3\u91CA\u4E00\u4E0B\u3002</p><p>\u5728\u4E00\u4E2A\u91D1\u878D\u7CFB\u7EDF\u4E2D\uFF0C\u6709\u4E24\u4E2A\u4E1A\u52A1\u9886\u57DF\u6A21\u578B\uFF0C\u7528\u6237\u548C\u94B1\u5305\u3002\u8FD9\u4E24\u4E2A\u4E1A\u52A1\u9886\u57DF\u6A21\u578B\u90FD\u5BF9\u5916\u66B4\u9732\u4E86\u4E00\u7CFB\u5217\u63A5\u53E3\uFF0C\u6BD4\u5982\u7528\u6237\u7684\u589E\u5220\u6539\u67E5\u63A5\u53E3\u3001\u94B1\u5305\u7684\u589E\u5220\u6539\u67E5\u63A5\u53E3\u3002\u5047\u8BBE\u6709\u8FD9\u6837\u4E00\u4E2A\u4E1A\u52A1\u573A\u666F\uFF1A\u5728\u7528\u6237\u6CE8\u518C\u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u4E0D\u4EC5\u4F1A\u521B\u5EFA\u7528\u6237\uFF08\u5728\u6570\u636E\u5E93 User \u8868\u4E2D\uFF09\uFF0C\u8FD8\u4F1A\u7ED9\u7528\u6237\u521B\u5EFA\u4E00\u4E2A\u94B1\u5305\uFF08\u5728\u6570\u636E\u5E93\u7684 Wallet \u8868\u4E2D\uFF09\u3002</p><p>\u5BF9\u4E8E\u8FD9\u6837\u4E00\u4E2A\u7B80\u5355\u7684\u4E1A\u52A1\u9700\u6C42\uFF0C\u6211\u4EEC\u53EF\u4EE5\u901A\u8FC7\u4F9D\u6B21\u8C03\u7528\u7528\u6237\u7684\u521B\u5EFA\u63A5\u53E3\u548C\u94B1\u5305\u7684\u521B\u5EFA\u63A5\u53E3\u6765\u5B8C\u6210\u3002\u4F46\u662F\uFF0C\u7528\u6237\u6CE8\u518C\u9700\u8981\u652F\u6301\u4E8B\u52A1\uFF0C\u4E5F\u5C31\u662F\u8BF4\uFF0C\u521B\u5EFA\u7528\u6237\u548C\u94B1\u5305\u7684\u4E24\u4E2A\u64CD\u4F5C\uFF0C\u8981\u4E48\u90FD\u6210\u529F\uFF0C\u8981\u4E48\u90FD\u5931\u8D25\uFF0C\u4E0D\u80FD\u4E00\u4E2A\u6210\u529F\u3001\u4E00\u4E2A\u5931\u8D25\u3002</p><p>\u8981\u652F\u6301\u4E24\u4E2A\u63A5\u53E3\u8C03\u7528\u5728\u4E00\u4E2A\u4E8B\u52A1\u4E2D\u6267\u884C\uFF0C\u662F\u6BD4\u8F83\u96BE\u5B9E\u73B0\u7684\uFF0C\u8FD9\u6D89\u53CA\u5206\u5E03\u5F0F\u4E8B\u52A1\u95EE\u9898\u3002\u867D\u7136\u6211\u4EEC\u53EF\u4EE5\u901A\u8FC7\u5F15\u5165\u5206\u5E03\u5F0F\u4E8B\u52A1\u6846\u67B6\u6216\u8005\u4E8B\u540E\u8865\u507F\u7684\u673A\u5236\u6765\u89E3\u51B3\uFF0C\u4F46\u4EE3\u7801\u5B9E\u73B0\u90FD\u6BD4\u8F83\u590D\u6742\u3002\u800C\u6700\u7B80\u5355\u7684\u89E3\u51B3\u65B9\u6848\u662F\uFF0C\u5229\u7528\u6570\u636E\u5E93\u4E8B\u52A1\u6216\u8005 Spring \u6846\u67B6\u63D0\u4F9B\u7684\u4E8B\u52A1\uFF08\u5982\u679C\u662F Java \u8BED\u8A00\u7684\u8BDD\uFF09\uFF0C\u5728\u4E00\u4E2A\u4E8B\u52A1\u4E2D\uFF0C\u6267\u884C\u521B\u5EFA\u7528\u6237\u548C\u521B\u5EFA\u94B1\u5305\u8FD9\u4E24\u4E2A SQL \u64CD\u4F5C\u3002\u8FD9\u5C31\u8981\u6C42\u4E24\u4E2A SQL \u64CD\u4F5C\u8981\u5728\u4E00\u4E2A\u63A5\u53E3\u4E2D\u5B8C\u6210\uFF0C\u6240\u4EE5\uFF0C\u6211\u4EEC\u53EF\u4EE5\u501F\u9274\u95E8\u9762\u6A21\u5F0F\u7684\u601D\u60F3\uFF0C\u518D\u8BBE\u8BA1\u4E00\u4E2A\u5305\u88F9\u8FD9\u4E24\u4E2A\u64CD\u4F5C\u7684\u65B0\u63A5\u53E3\uFF0C\u8BA9\u65B0\u63A5\u53E3\u5728\u4E00\u4E2A\u4E8B\u52A1\u4E2D\u6267\u884C\u4E24\u4E2A SQL \u64CD\u4F5C\u3002</p><h2 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h2><p>\u6211\u4EEC\u77E5\u9053\uFF0C\u7C7B\u3001\u6A21\u5757\u3001\u7CFB\u7EDF\u4E4B\u95F4\u7684\u201C\u901A\u4FE1\u201D\uFF0C\u4E00\u822C\u90FD\u662F\u901A\u8FC7\u63A5\u53E3\u8C03\u7528\u6765\u5B8C\u6210\u7684\u3002\u63A5\u53E3\u8BBE\u8BA1\u7684\u597D\u574F\uFF0C\u76F4\u63A5\u5F71\u54CD\u5230\u7C7B\u3001\u6A21\u5757\u3001\u7CFB\u7EDF\u662F\u5426\u597D\u7528\u3002\u6240\u4EE5\uFF0C\u6211\u4EEC\u8981\u591A\u82B1\u70B9\u5FC3\u601D\u5728\u63A5\u53E3\u8BBE\u8BA1\u4E0A\u3002\u6211\u7ECF\u5E38\u8BF4\uFF0C<strong>\u5B8C\u6210\u63A5\u53E3\u8BBE\u8BA1\uFF0C\u5C31\u76F8\u5F53\u4E8E\u5B8C\u6210\u4E86\u4E00\u534A\u7684\u5F00\u53D1\u4EFB\u52A1\u3002\u53EA\u8981\u63A5\u53E3\u8BBE\u8BA1\u5F97\u597D\uFF0C\u90A3\u4EE3\u7801\u5C31\u5DEE\u4E0D\u5230\u54EA\u91CC\u53BB\u3002</strong></p><p>\u63A5\u53E3\u7C92\u5EA6\u8BBE\u8BA1\u5F97\u592A\u5927\uFF0C\u592A\u5C0F\u90FD\u4E0D\u597D\u3002\u592A\u5927\u4F1A\u5BFC\u81F4\u63A5\u53E3\u4E0D\u53EF\u590D\u7528\uFF0C\u592A\u5C0F\u4F1A\u5BFC\u81F4\u63A5\u53E3\u4E0D\u6613\u7528\u3002\u5728\u5B9E\u9645\u7684\u5F00\u53D1\u4E2D\uFF0C\u63A5\u53E3\u7684\u53EF\u590D\u7528\u6027\u548C\u6613\u7528\u6027\u9700\u8981\u201C\u5FAE\u5999\u201D\u7684\u6743\u8861\u3002\u9488\u5BF9\u8FD9\u4E2A\u95EE\u9898\uFF0C\u6211\u7684\u4E00\u4E2A\u57FA\u672C\u7684\u5904\u7406\u539F\u5219\u662F\uFF0C<strong>\u5C3D\u91CF\u4FDD\u6301\u63A5\u53E3\u7684\u53EF\u590D\u7528\u6027\uFF0C\u4F46\u9488\u5BF9\u7279\u6B8A\u60C5\u51B5\uFF0C\u5141\u8BB8\u63D0\u4F9B\u5197\u4F59\u7684\u95E8\u9762\u63A5\u53E3\uFF0C\u6765\u63D0\u4F9B\u66F4\u6613\u7528\u7684\u63A5\u53E3</strong>\u3002</p><p>\u95E8\u9762\u6A21\u5F0F\u9664\u4E86\u89E3\u51B3\u63A5\u53E3\u6613\u7528\u6027\u95EE\u9898\u4E4B\u5916\uFF0C\u6211\u4EEC\u4ECA\u5929\u8FD8\u8BB2\u5230\u4E86\u5176\u4ED6 2 \u4E2A\u5E94\u7528\u573A\u666F\uFF0C\u7528\u5B83\u6765\u89E3\u51B3\u6027\u80FD\u95EE\u9898\u548C\u5206\u5E03\u5F0F\u4E8B\u52A1\u95EE\u9898\u3002</p><h2 id="\u601D\u8003\u9898" tabindex="-1"><a class="header-anchor" href="#\u601D\u8003\u9898" aria-hidden="true">#</a> \u601D\u8003\u9898</h2><p>\u9002\u914D\u5668\u6A21\u5F0F\u548C\u95E8\u9762\u6A21\u5F0F\u7684\u5171\u540C\u70B9\u662F\uFF0C\u5C06\u4E0D\u597D\u7528\u7684\u63A5\u53E3\u9002\u914D\u6210\u597D\u7528\u7684\u63A5\u53E3\u3002\u4F60\u53EF\u4EE5\u8BD5\u7740\u603B\u7ED3\u4E00\u4E0B\u5B83\u4EEC\u7684\u533A\u522B\u5417\uFF1F</p><blockquote><p>\u9002\u914D\u5668\u662F\u505A\u63A5\u53E3\u8F6C\u6362\uFF0C\u89E3\u51B3\u7684\u662F\u539F\u63A5\u53E3\u548C\u76EE\u6807\u63A5\u53E3\u4E0D\u5339\u914D\u7684\u95EE\u9898\u3002</p><p>\u95E8\u9762\u6A21\u5F0F\u505A\u63A5\u53E3\u6574\u5408\uFF0C\u89E3\u51B3\u7684\u662F\u591A\u63A5\u53E3\u8C03\u7528\u5E26\u6765\u7684\u95EE\u9898\u3002</p></blockquote><p>\u5728\u4F60\u8FC7\u5F80\u7684\u9879\u76EE\u5F00\u53D1\u4E2D\uFF0C\u6709\u6CA1\u6709\u9047\u5230\u8FC7\u4E0D\u5408\u7406\u7684\u63A5\u53E3\u9700\u6C42\uFF1F\u53C8\u6216\u8005\uFF0C\u6709\u6CA1\u6709\u9047\u5230\u8FC7\u975E\u5E38\u96BE\u7528\u7684\u63A5\u53E3\uFF1F\u53EF\u4EE5\u7559\u8A00\u201C\u5410\u69FD\u201D\u4E00\u4E0B\u3002</p><blockquote><p>\u8BE5\u95EE\u9898\u4FDD\u7559\u3002</p></blockquote>',40);function d(t,h){return r}var s=a(p,[["render",d],["__file","Facade.html.vue"]]);export{s as default};
